"use client";

import React from "react";
import { motion } from "framer-motion";
import { MapPin, Mail, Clock, School, User } from "lucide-react";

export default function DoctorCard({ doctor }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      className="saas-card overflow-hidden"
    >
      <div className="p-6">
        <div className="flex items-start justify-between mb-4">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-full bg-indigo-50 dark:bg-indigo-500/10 flex items-center justify-center text-indigo-600">
              <User size={24} />
            </div>
            <div>
              <h3 className="text-lg font-semibold text-slate-900 dark:text-white leading-tight">
                {doctor.name}
              </h3>
              <p className="text-sm text-slate-500 dark:text-slate-400 mt-0.5">
                {doctor.department}
              </p>
            </div>
          </div>
        </div>

        <div className="space-y-3 pt-2 border-t border-slate-100 dark:border-slate-800/50">
          <div className="flex items-center gap-3 text-sm text-slate-600 dark:text-slate-400">
            <School size={16} className="text-slate-400" />
            <span>{doctor.school}</span>
          </div>
          <div className="flex items-center gap-3 text-sm text-slate-600 dark:text-slate-400">
            <MapPin size={16} className="text-slate-400" />
            <span>Office: {doctor.office || "N/A"}</span>
          </div>
          <div className="flex items-center gap-3 text-sm text-indigo-600 dark:text-indigo-400 font-medium">
            <Mail size={16} />
            <a href={`mailto:${doctor.email}`} className="hover:underline">
              {doctor.email}
            </a>
          </div>
        </div>

        <div className="mt-6">
          <div className="flex items-center gap-2 mb-3">
            <Clock size={14} className="text-slate-400" />
            <span className="text-xs font-bold uppercase tracking-wider text-slate-400">
              Office Hours
            </span>
          </div>
          <div className="bg-slate-50/50 dark:bg-slate-950/30 rounded-xl p-3 space-y-2 border border-slate-100 dark:border-slate-800/50">
            {Object.entries(doctor.office_hours).map(([day, hours]) => (
              <div key={day} className="flex justify-between items-start text-xs">
                <span className="font-bold text-slate-700 dark:text-slate-300 w-20">{day}</span>
                <span className="text-slate-500 dark:text-slate-500 flex-1 text-right">{hours}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </motion.div>
  );
}
